def advance(self) -> str:
ch = self.source[self.current]  # READ
self.current += 1               # MUTATE current
if ch == '\n':
self.line += 1              # MUTATE line
self.column = 1             # MUTATE column
else:
self.column += 1            # MUTATE column
return ch                       # RETURN consumed char

python
def peek(self) -> str:
if self.is_at_end():
return '\0'                 # EOF sentinel — no read
return self.source[self.current]  # READ only
